      border-radius: 15px;
      font-size: 12px;
      color: var(--dark-primary);
    }

    /* CTA */
    .cta-section {
      background: var(--dark-primary);
      text-align: center;
      padding: 80px 0;

      h2 {
        color: white;
        margin-bottom: 15px;
      }

      p {
        color: rgba(255, 255, 255, 0.9);
